import type { ElementScores, ElementType, IdentityInfo, Question } from './types'
import { ELEMENT_MAP_REVERSE } from './types'

// ============================================================================
// v2.0 辅助函数
// ============================================================================

/**
 * 解析四维倾向文本为4位二进制数组
 * @param text 四维倾向文本，如"出世+文+江湖+权变"
 * @returns 4位数组[0,0,0,1]，维度顺序：出世/入世(0/1)、文/武(0/1)、江湖/庙堂(0/1)、守正/权变(0/1)
 * @throws 如果文本格式无效
 */
export function parseFourDimensionText(text: string): number[] {
  if (!text || typeof text !== 'string') {
    return [0, 0, 0, 0];
  }
  
  // 使用"+"分割各个维度
  const parts = text.split('+').map(part => part.trim());
  if (parts.length !== 4) {
    // 尝试其他分隔符或返回默认值
    console.warn(`Invalid four dimension text format: "${text}". Expected 4 parts separated by '+'.`);
    return [0, 0, 0, 0];
  }
  
  const result: number[] = [];
  
  // 映射关系
  const dimensionMaps = [
    // 维度0: 出世(0) vs 入世(1)
    { '出世': 0, '入世': 1 },
    // 维度1: 文(0) vs 武(1)
    { '文': 0, '武': 1 },
    // 维度2: 江湖(0) vs 庙堂(1)
    { '江湖': 0, '庙堂': 1 },
    // 维度3: 守正(0) vs 权变(1)
    { '守正': 0, '权变': 1 }
  ];
  
  for (let i = 0; i < 4; i++) {
    const part = parts[i];
    const map = dimensionMaps[i];
    
    if (part in map) {
      const value = map[part as keyof typeof map];
      if (value !== undefined) {
        result.push(value);
      } else {
        result.push(0);
      }
    } else {
      // 未知的值，默认设为0
      console.warn(`Unknown dimension value "${part}" at position ${i}. Using default 0.`);
      result.push(0);
    }
  }
  
  return result;
}

/**
 * 计算用户四维编码（4位二进制）
 * @param questions 题目列表
 * @param selectedOptions 用户选择的选项索引数组
 * @returns 4位二进制字符串，如"0001"
 */
export function calculateDimensionCode(
  questions: Question[], 
  selectedOptions: number[]
): string {
  // 初始化维度计数：每个维度统计0和1的数量
  const dimensionCounts = Array(4).fill(0).map(() => ({ zero: 0, one: 0 }));
  
  // 遍历所有选择
  for (let i = 0; i < questions.length; i++) {
    const question = questions[i];
    const selectedIndex = selectedOptions[i];
    
    if (selectedIndex >= 0 && selectedIndex < question.options.length) {
      const option = question.options[selectedIndex];
      
      // 如果选项有四维倾向文本，解析并统计
      if (option.fourDimensionText) {
        const dimensionValues = parseFourDimensionText(option.fourDimensionText);
        
        for (let dim = 0; dim < 4; dim++) {
          if (dimensionValues[dim] === 0) {
            dimensionCounts[dim].zero++;
          } else if (dimensionValues[dim] === 1) {
            dimensionCounts[dim].one++;
          }
        }
      }
    }
  }
  
  // 生成4位二进制编码
  let code = '';
  for (let dim = 0; dim < 4; dim++) {
    const counts = dimensionCounts[dim];
    
    // 如果有统计数据，取多数值；如果平局，优先取0；如果无数据，默认0
    if (counts.zero + counts.one === 0) {
      code += '0'; // 默认值
    } else if (counts.one > counts.zero) {
      code += '1';
    } else {
      code += '0'; // 平局或zero >= one时取0
    }
  }
  
  return code;
}

// ============================================================================
// v2.0 核心匹配函数
// ============================================================================

/**
 * v2.0精准匹配：使用四维编码+五行主元素匹配身份
 * @param scores 五行分数
 * @param dimensionCode 四维编码（4位二进制字符串）
 * @param identities 所有身份列表
 * @returns 匹配的身份信息
 */
export function determineIdentityV2(
  scores: ElementScores,
  dimensionCode: string,
  identities: IdentityInfo[]
): IdentityInfo {
  // 1. 确定五行主元素
  const dominantElement = getDominantElement(scores);
  const dominantElementCN = ELEMENT_MAP_REVERSE[dominantElement];
  
  // 2. 构建目标ID：dimensionCode + "-" + dominantElementCN
  const targetId = `${dimensionCode}-${dominantElementCN}`;
  
  // 3. 查找匹配的身份（优先匹配id，其次匹配code和element组合）
  for (const identity of identities) {
    // 优先匹配id字段
    if (identity.id === targetId) {
      return identity;
    }
  }
  
  // 4. 如果没有精确匹配，尝试模糊匹配
  // 4.1 首先匹配相同四维编码的身份
  const matchingByCode = identities.filter(identity => 
    identity.code && identity.code === dimensionCode
  );
  
  if (matchingByCode.length > 0) {
    // 在相同编码的身份中，选择五行匹配的
    const matchingByElement = matchingByCode.filter(identity => 
      identity.element === dominantElement
    );
    
    if (matchingByElement.length > 0) {
      return matchingByElement[0];
    }
    
    // 如果五行不匹配，返回第一个相同编码的身份
    return matchingByCode[0];
  }
  
  // 4.2 如果没有相同编码的身份，回退到v1.1方案A
  console.warn(`No identity found for ID: ${targetId}. Falling back to v1.1 logic.`);
  return determineIdentityV1(scores, identities);
}

// ============================================================================
// v1.1 原有函数（保持向后兼容）
// ============================================================================

/**
 * 计算五行分数
 * @param questions 题目列表
 * @param selectedOptions 用户选择的选项索引数组（长度与questions相同）
 * @returns 五行分数对象
 */
export function calculateScores(
  questions: Question[], 
  selectedOptions: number[]
): ElementScores {
  const scores: ElementScores = {
    metal: 0,
    wood: 0,
    water: 0,
    fire: 0,
    earth: 0
  }

  // 累加每道题的五行权重
  for (let i = 0; i < questions.length; i++) {
    const question = questions[i]
    const selectedIndex = selectedOptions[i]
    
    if (selectedIndex >= 0 && selectedIndex < question.options.length) {
      const option = question.options[selectedIndex]
      const weights = option.weights
      
      // 累加五行得分
      scores.metal += weights.metal || 0
      scores.wood += weights.wood || 0
      scores.water += weights.water || 0
      scores.fire += weights.fire || 0
      scores.earth += weights.earth || 0
    }
  }

  return scores
}

/**
 * 找出最高分的五行
 * @param scores 五行分数
 * @returns 最高分的五行元素
 */
export function getDominantElement(scores: ElementScores): ElementType {
  const elements: ElementType[] = ['metal', 'wood', 'water', 'fire', 'earth']
  let dominant: ElementType = 'metal'
  let maxScore = -1
  
  for (const element of elements) {
    if (scores[element] > maxScore) {
      maxScore = scores[element]
      dominant = element
    }
  }
  
  return dominant
}

/**
 * 获取五行分数分布（百分比）
 * @param scores 五行分数
 * @returns 五行分数百分比分布
 */
export function getElementDistribution(scores: ElementScores): Record<ElementType, number> {
  const elements: ElementType[] = ['metal', 'wood', 'water', 'fire', 'earth']
  const total = elements.reduce((sum, el) => sum + scores[el], 0)
  
  if (total === 0) {
    return {
      metal: 20,
      wood: 20,
      water: 20,
      fire: 20,
      earth: 20
    }
  }
  
  const distribution: Record<ElementType, number> = {
    metal: 0,
    wood: 0,
    water: 0,
    fire: 0,
    earth: 0
  }
  
  for (const element of elements) {
    distribution[element] = Math.round((scores[element] / total) * 100)
  }
  
  return distribution
}

/**
 * 根据五行分数确定身份（简化版 - 方案A）
 * 策略：1. 选择主要五行对应的身份组 2. 返回组内第一个身份
 * @param scores 五行分数
 * @param identities 所有身份列表
 * @returns 匹配的身份信息
 */
export function determineIdentityV1(
  scores: ElementScores,
  identities: IdentityInfo[]
): IdentityInfo {
  // 1. 找出最高分的五行
  const dominantElement = getDominantElement(scores)
  
  // 2. 筛选出主要五行匹配的身份
  const matchingIdentities = identities.filter(identity => 
    identity.element === dominantElement
  )
  
  if (matchingIdentities.length === 0) {
    // 如果没有匹配的，返回第一个身份
    return identities[0]
  }
  
  // 3. 方案A：直接返回第一个匹配的身份（最简单的映射）
  return matchingIdentities[0]
}

/**
 * 计算五行平衡度
 * @param scores 五行分数
 * @returns 平衡度百分比 (0-100)
 */
export function calculateBalance(scores: ElementScores): number {
  const values = Object.values(scores)
  const max = Math.max(...values)
  const min = Math.min(...values)

  if (max === 0) return 0

  // 差值越小，平衡度越高
  const diff = max - min
  const balance = Math.max(0, 100 - diff * 10)

  return Math.round(balance)
}

/**
 * 获取五行相生相克关系
 * @param element 五行元素
 * @returns 相生和相克元素
 */
export function getElementRelations(element: ElementType): { promotes: ElementType; weakens: ElementType } {
  const relations: Record<ElementType, { promotes: ElementType; weakens: ElementType }> = {
    metal: { promotes: 'water', weakens: 'wood' },
    wood: { promotes: 'fire', weakens: 'earth' },
    water: { promotes: 'wood', weakens: 'fire' },
    fire: { promotes: 'earth', weakens: 'water' },
    earth: { promotes: 'metal', weakens: 'wood' }
  }

  return relations[element]
}

/**
 * 获取五行描述
 * @param element 五行元素
 * @returns 五行描述信息
 */
export function getElementDescription(element: ElementType): {
  nameCN: string
  characteristics: string[]
  symbol: string
} {
  const elementInfo: Record<ElementType, { nameCN: string; characteristics: string[]; symbol: string }> = {
    metal: {
      nameCN: '金',
      characteristics: ['决断', '秩序', '权威', '刚毅'],
      symbol: '⚔️'
    },
    wood: {
      nameCN: '木',
      characteristics: ['成长', '创造', '温和', '包容'],
      symbol: '🌳'
    },
    water: {
      nameCN: '水',
      characteristics: ['智慧', '流动', '灵活', '适应'],
      symbol: '💧'
    },
    fire: {
      nameCN: '火',
      characteristics: ['热情', '行动', '变革', '感染力'],
      symbol: '🔥'
    },
    earth: {
      nameCN: '土',
      characteristics: ['稳定', '实际', '责任', '沉稳'],
      symbol: '⛰️'
    }
  }
  
  return elementInfo[element] || { nameCN: '未知', characteristics: [], symbol: '✨' }
}

// ============================================================================
// 自动检测和整合函数
// ============================================================================

/**
 * 自动检测数据版本并确定身份
 * 逻辑：如果有fourDimensionText数据，使用v2.0算法；否则使用v1.1方案A
 * @param questions 题目列表
 * @param selectedOptions 用户选择的选项索引数组
 * @param identities 所有身份列表
 * @returns 匹配的身份信息
 */
export function determineIdentityAuto(
  questions: Question[],
  selectedOptions: number[],
  identities: IdentityInfo[]
): IdentityInfo {
  // 检查是否有四维数据
  const hasFourDimensionData = questions.some(question =>
    question.options.some(option => option.fourDimensionText)
  )
  
  if (hasFourDimensionData) {
    // 使用v2.0算法
    const scores = calculateScores(questions, selectedOptions)
    const dimensionCode = calculateDimensionCode(questions, selectedOptions)
    return determineIdentityV2(scores, dimensionCode, identities)
  } else {
    // 使用v1.1算法
    const scores = calculateScores(questions, selectedOptions)
    return determineIdentityV1(scores, identities)
  }
}

/**
 * 整合函数：计算完整结果（五行分数、四维编码、匹配身份）
 * @param questions 题目列表
 * @param selectedOptions 用户选择的选项索引数组
 * @param identities 所有身份列表
 * @returns 匹配的身份信息
 */
export function calculateResult(
  questions: Question[],
  selectedOptions: number[],
  identities: IdentityInfo[]
): IdentityInfo {
  return determineIdentityAuto(questions, selectedOptions, identities)
}

/**
 * 向后兼容的determineIdentity函数（别名）
 * 注意：为了保持向后兼容，此函数使用自动检测逻辑
 * @deprecated 建议使用determineIdentityAuto或calculateResult
 */
export function determineIdentity(
  scores: ElementScores,
  identities: IdentityInfo[]
): IdentityInfo {
  // 为了保持API兼容，但无法获取questions和selectedOptions
  // 这里只能回退到v1.1方案
  console.warn('Legacy determineIdentity() called without questions and selectedOptions. Falling back to v1.1 logic.')
  return determineIdentityV1(scores, identities)
}

/**
 * 完整结果计算（返回所有中间数据）
 * @param questions 题目列表
 * @param selectedOptions 用户选择的选项索引数组
 * @param identities 所有身份列表
 * @returns 完整结果对象
 */
export function calculateCompleteResult(
  questions: Question[],
  selectedOptions: number[],
  identities: IdentityInfo[]
): {
  scores: ElementScores
  distribution: Record<ElementType, number>
  dominantElement: ElementType
  dimensionCode: string | null
  identity: IdentityInfo
  balance: number
  elementDescription: ReturnType<typeof getElementDescription>
  hasFourDimensionData: boolean
} {
  const scores = calculateScores(questions, selectedOptions)
  const distribution = getElementDistribution(scores)
  const dominantElement = getDominantElement(scores)
  const balance = calculateBalance(scores)
  const elementDescription = getElementDescription(dominantElement)
  
  // 检查是否有四维数据
  const hasFourDimensionData = questions.some(question =>
    question.options.some(option => option.fourDimensionText)
  )
  
  let dimensionCode: string | null = null
  let identity: IdentityInfo
  
  if (hasFourDimensionData) {
    dimensionCode = calculateDimensionCode(questions, selectedOptions)
    identity = determineIdentityV2(scores, dimensionCode, identities)
  } else {
    identity = determineIdentityV1(scores, identities)
  }
  
  return {
    scores,
    distribution,
    dominantElement,
    dimensionCode,
    identity,
    balance,
    elementDescription,
    hasFourDimensionData
  }
}